(()=>{"use strict";const defaultConfig={maxtrait:2};const drawRandomInRange=ranges=>{const options=ranges.reduce(((opt,{min:min,max:max,prob:prob})=>{opt[`${min}-${max}`]=prob;return opt}),{});const range=drawOption(options);const[min,max]=range.split("-").map(Number);return randomInt(min,max)};const updateAttributes=(chosenProfile,npcAttrs,attrs)=>{if(chosenProfile){const{affects:affects={},limits:limits={}}=chosenProfile;Object.entries(affects).forEach((([attrKey,attrValue])=>{npcAttrs[attrKey]=(npcAttrs[attrKey]??0)+attrValue}));Object.entries(limits).forEach((([attrKey,limit])=>{if(limit.min)attrs[attrKey].min=limit.min;if(limit.max)attrs[attrKey].max=limit.max}))}};const generateNPC=(profiles,attrs,traits,config={},defaults={},pinned={})=>{config=Object.assign({},defaultConfig,config);const npcAttrs=Object.entries(attrs).reduce(((acc,[key,value])=>{const pinnedVal=pinned[key];acc[key]=pinnedVal&&Number.isFinite(pinnedVal)?pinnedVal:value.ranges?drawRandomInRange(value.ranges):randomInt(value.min,value.max);return acc}),{});const npcProfiles=Object.entries(profiles).reduce(((acc,[key,value])=>{const pinnedVal=pinned[key];const selectedValue=pinnedVal?pinnedVal:Array.isArray(value)&&typeof value[0]==="object"?drawOption(value.reduce(((opt,{value:value,prob:prob})=>({...opt,[value]:prob})),{})):value.random();acc[key]=selectedValue;if(Array.isArray(value)&&typeof value[0]==="object"){const chosenProfile=value.find((opt=>opt.value===selectedValue));updateAttributes(chosenProfile,npcAttrs,attrs)}return acc}),{});const applies=pinned.traits?[...pinned.traits]:[];const traitMap={};let availableTraits=[...traits].filter((trait=>!applies.includes(trait.name)));while(applies.length<config.maxtrait&&availableTraits.length>0){const trait=availableTraits.random();if(!traitMap[trait.name]){applies.push(trait.name);traitMap[trait.name]=trait;availableTraits=availableTraits.filter((t=>t!==trait))}availableTraits=availableTraits.filter((trait=>!applies.some((appliedTrait=>{const applied=traitMap[appliedTrait];return applied?.exclusive?.includes(trait.name)||trait.exclusive?.includes(appliedTrait)}))))}Object.values(traitMap).forEach((({affects:affects={}})=>{Object.entries(affects).forEach((([key,value])=>{if(npcAttrs[key]!==undefined){npcAttrs[key]+=value}}))}));Object.keys(npcAttrs).forEach((key=>{const{min:min,max:max}=attrs[key];npcAttrs[key]=applyBounds(npcAttrs[key],min,max)}));return{...npcProfiles,...defaults,...npcAttrs,traits:applies}};Macro.add("pushnpc",{tags:null,handler(){if(this.args.length<2){return this.error("Not enough arguments provided. At least two arguments are required.")}const cleanArg=arg=>arg.replace(/["']/g,"").trim();const parts=this.args.raw.trim().split(" ");const varName=cleanArg(parts[0]);if(!isValidVariable(varName)){return this.error("argument must be a story or temporary variable!")}let arr=State.getVar(varName);if(!Array.isArray(arr)){return this.error("Expected an array but received: "+typeof arr)}if(!setup.profiles||!setup.attrs||!setup.traits){return this.error("setup.profiles, setup.attrs, and setup.traits must be defined!")}const times=parseInt(parts[1]);const startIndex=arr.length;const pinned=this.args[2]&&typeof this.args[2]==="object"&&!Array.isArray(this.args[2])?this.args[2]:convertToObject(this.args.slice(2));repeat(times,(_=>{arr.push(generateNPC(setup.profiles,setup.attrs,setup.traits,setup.config||{},setup.defaults||{},pinned))}));const endIndex=arr.length-1;WikiVars({start:startIndex,end:endIndex},this)}});setup.generateNPC=generateNPC;window.generateNPC=window.generateNPC||generateNPC})();
/* End 生成NPC */